import React, { useState, useContext } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { CloudCog, LogIn, DollarSign, Boxes, Activity } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { AppCtx } from '../App';
import { getErrorMessage } from '../api/errors';
import AssetIcon from '../components/AssetIcon';
import { PAGE_ICONS } from '../config/assetIcons';

const FEATURES = [
  { icon: DollarSign, label: 'Cost insights', color: '#22c55e' },
  { icon: Boxes, label: 'Resource inventory', color: '#3b82f6' },
  { icon: Activity, label: 'Optimization findings', color: '#a78bfa' },
];

export default function Login() {
  const { login, isAuthenticated, loading } = useAuth();
  const { reloadSubscriptions } = useContext(AppCtx);
  const location = useLocation();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  const from = location.state?.from?.pathname || '/';

  if (!loading && isAuthenticated) {
    return <Navigate to={from} replace />;
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSubmitting(true);
    try {
      await login(username.trim(), password);
      reloadSubscriptions?.();
    } catch (err) {
      setError(getErrorMessage(err, 'Sign in failed. Check your username and password.'));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-page__bg" aria-hidden="true">
        <div className="login-page__orb login-page__orb--1" />
        <div className="login-page__orb login-page__orb--2" />
        <div className="login-page__orb login-page__orb--3" />
        <div className="login-page__grid" />
      </div>

      <div className="login-layout">
        <section className="login-hero">
          <div className="login-hero__badge">Azure cost optimization</div>
          <h2 className="login-hero__title">
            See spend, inventory, and savings in one place
          </h2>
          <p className="login-hero__desc">
            Track Azure costs, browse synced resources, and act on optimization findings — all from a single dashboard.
          </p>
          <ul className="login-hero__features">
            {FEATURES.map(({ icon: Icon, label, color }) => (
              <li key={label} style={{ '--feature-color': color }}>
                <span className="login-hero__feature-icon">
                  <Icon size={16} />
                </span>
                {label}
              </li>
            ))}
          </ul>
        </section>

        <div className="login-card">
          <div className="login-card__brand">
            <div className="sidebar-logo__icon login-card__logo">
              <AssetIcon iconKey={PAGE_ICONS.logo} size={28} fallback={<CloudCog size={24} />} />
            </div>
            <h1>Azure FinOps</h1>
            <p>Sign in with your app username and password.</p>
          </div>

          <form className="login-form" onSubmit={handleSubmit}>
            {error && (
              <div className="alert alert--danger" role="alert">
                {error}
              </div>
            )}

            <label className="login-form__field">
              <span>Username</span>
              <input
                type="text"
                autoComplete="username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Enter username"
                required
                disabled={submitting}
              />
            </label>

            <label className="login-form__field">
              <span>Password</span>
              <input
                type="password"
                autoComplete="current-password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter password"
                required
                disabled={submitting}
              />
            </label>

            <button type="submit" className="btn btn-primary login-form__submit" disabled={submitting}>
              <LogIn size={16} />
              {submitting ? 'Signing in…' : 'Sign in'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
